"use client"

import { useEffect } from "react"
import L from "leaflet"
import type { GeoJsonObject } from "geojson"
import { GeoJSON, MapContainer, TileLayer, useMap } from "react-leaflet"

function FitData({ geojson }: { geojson: Record<string, unknown> }) {
  const map = useMap()
  useEffect(() => {
    const bounds = L.geoJSON(geojson as unknown as GeoJsonObject).getBounds()
    if (bounds.isValid()) map.fitBounds(bounds, { padding: [24, 24], maxZoom: 15 })
  }, [geojson, map])
  return null
}

export default function HydraulicHotspotMapImpl({ geojson }: { geojson: Record<string, unknown> }) {
  return (
    <MapContainer center={[-6.2, 35.7]} zoom={7} scrollWheelZoom className="h-80 w-full">
      <TileLayer attribution="&copy; OpenStreetMap contributors" url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
      <GeoJSON key={JSON.stringify(geojson).length} data={geojson as unknown as GeoJsonObject} style={(feature) => ({ color: feature?.properties?.risk_level === "high" ? "#dc2626" : "#f59e0b", weight: 5, opacity: 0.9 })} onEachFeature={(feature, layer) => { const p = feature.properties || {}; layer.bindPopup(`<strong>${p.pipe_id || "Risk location"}</strong><br/>Risk: ${p.risk_level || "Not classified"}<br/>Score: ${p.risk_score ?? "N/A"}`) }} />
      <FitData geojson={geojson} />
    </MapContainer>
  )
}
